(()=>{document.addEventListener("DOMContentLoaded",()=>{let i=new Set(["INPUT","TEXTAREA","SELECT"]);document.querySelectorAll(".input-search").forEach(e=>{let t=e.querySelector(".input-search-field");t&&(t.addEventListener("focus",()=>{e.classList.add("is-open")}),t.addEventListener("blur",()=>{t.value.trim()||e.classList.remove("is-open")}))}),document.addEventListener("keydown",e=>{if(e.key!=="/"||e.metaKey||e.ctrlKey||e.altKey)return;let t=document.activeElement;if(i.has(t.tagName)||t.isContentEditable)return;let n=document.querySelector(".input-search-field");n&&(e.preventDefault(),n.focus())})});})();
